package com.khanh.fooddelivery.restaurant_service.entity;
import com.khanh.fooddelivery.restaurant_service.common.entity.BaseAuditEntity; import com.khanh.fooddelivery.restaurant_service.enums.BankAccountVerificationStatus; import jakarta.persistence.*; import lombok.*; import java.util.UUID;
@Entity @Table(name="restaurant_bank_accounts") @Getter @Setter @NoArgsConstructor
public class RestaurantBankAccount extends BaseAuditEntity {@Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="restaurant_id") private Restaurant restaurant; @Column(nullable=false) private String bankCode; private String bankName; @Column(nullable=false) private String accountNumber; @Column(nullable=false) private String accountHolderName; @Column(nullable=false) private boolean defaultAccount; @Enumerated(EnumType.STRING) @Column(nullable=false) private BankAccountVerificationStatus verificationStatus; @Version private long version; @PrePersist void id(){if(id==null)id=UUID.randomUUID();}}
